func (c *streamableClientConn) setMCPHeaders(req *http.Request) {
    c.mu.Lock()
    defer c.mu.Unlock()
    if c.initializedResult != nil {
        req.Header.Set(protocolVersionHeader, c.initializedResult.ProtocolVersion)
    }
    if c.sessionID != "" {
        req.Header.Set(sessionIDHeader, c.sessionID)
    }
}

